SELECT COUNT(1) FROM STUDENTS ST
ST.VISIBLE_FLG = 'true'
AND ST.LOGIN_ACCOUNT = #{loginAccount}

SELECT COUNT(1)
FROM STUDENTS ST

	ST.VISIBLE_FLG = 'true'

		AND ST.ID <> #{id}


		AND ST.LOGIN_ACCOUNT = #{loginAccount}

SELECT ST.ID, ST.LOGIN_ACCOUNT, ST.PASSWORD, ST.USERNAME, ST.DATE_OF_BIRTH, ST.EMAIL, ST.ROLE_ID, ST.UPDATED_TIME, ST.VISIBLE_FLG FROM STUDENTS ST
ST.VISIBLE_FLG = 'true'
AND ST.ID = #{id}

SELECT ST.ID, ST.LOGIN_ACCOUNT, ST.PASSWORD, ST.USERNAME, ST.DATE_OF_BIRTH, ST.EMAIL, ST.ROLE_ID, ST.UPDATED_TIME, ST.VISIBLE_FLG FROM STUDENTS ST
ST.VISIBLE_FLG = 'true'
AND ST.LOGIN_ACCOUNT = #{loginAccount}

